--
-- Issue #836: Scope order-confirmed customer email and add admin notification
--
-- Template 1 was seeded with receiver_type='*' which caused the SAME
-- customer-style "Thanks for your order, [BILLING_FIRSTNAME]!" message
-- to be sent to both the customer and the admin recipients defined in
-- ComponentParam admin_email. Per issue #836, the customer-facing copy
-- should only go to the customer, and admins should receive a separate
-- store-owner-focused notification with the order amount in the subject.
--
-- This migration:
--   1. Re-scopes template ID 1 to customer-only (only when its
--      receiver_type is still the install default '*' AND its subject
--      still matches the original seed - so customised rows are skipped)
--   2. INSERT IGNOREs a new template ID 4 (admin-only, orderstatus 1)
--      that mirrors template 1's structure but with admin-focused
--      banner copy and "New Order #[ORDERID] - [ORDERAMOUNT]" subject.
--
-- Tracking: GitHub issue #836
--

-- 1. Re-scope template 1 to customer-only
UPDATE `#__j2commerce_emailtemplates`
   SET `receiver_type` = 'customer'
 WHERE `j2commerce_emailtemplate_id` = 1
   AND `receiver_type` = '*'
   AND `subject` LIKE 'Thanks for your order, [BILLING_FIRSTNAME]!%';

-- 2. Add new admin-only order-confirmed notification (ID 4)
INSERT IGNORE INTO `#__j2commerce_emailtemplates` (`j2commerce_emailtemplate_id`, `email_type`, `receiver_type`, `orderstatus_id`, `group_id`, `paymentmethod`, `subject`, `body`, `body_json`, `body_source`, `body_source_file`, `custom_css`, `language`, `enabled`, `ordering`) VALUES (4,'transactional','admin','1','*','*','New Order #[ORDERID] - [ORDERAMOUNT]','<!-- J2Commerce New Order - Admin Template -->\r\n<style>\r\n  @media only screen and (max-width: 620px) {\r\n    .email-container { width: 100% !important;background-color: #ffffff !important;}\r\n    .mobile-padding { padding-left: 20px !important; padding-right: 20px !important; }\r\n    .address-col { display: block !important; width: 100% !important; padding: 0 0 16px 0 !important; }\r\n  }\r\n</style>\r\n\r\n<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: [EMAIL_BG_COLOR]; font-family: Arial, Helvetica, sans-serif;">\r\n  <tr>\r\n    <td align="center" style="padding: 30px 10px;">\r\n      <table class="email-container" width="600" cellpadding="0" cellspacing="0" border="0" style="max-width: 600px; width: 100%;background-color:#fff;">\r\n\r\n        <!-- Logo Bar -->\r\n        <tr>\r\n          <td style="padding: 20px 30px; background-color: #ffffff; border-radius: 12px 12px 0 0; text-align: center;">\r\n            [IF:STORE_LOGO_URL]\r\n            <a href="[SITEURL]" target="_blank">\r\n                <img src="[STORE_LOGO_URL]" alt="[SITENAME]" style="display: block; border: 0;height: [LOGO_MAX_HEIGHT]px; width:auto;" />\r\n            </a>\r\n            [/IF:STORE_LOGO_URL]\r\n            [IFNOT:STORE_LOGO_URL]\r\n            <a href="[SITEURL]" target="_blank" style="font-size: 22px; font-weight: bold; color: [ACCENT_COLOR]; text-decoration: none;">[SITENAME]</a>\r\n            [/IFNOT:STORE_LOGO_URL]\r\n          </td>\r\n        </tr>\r\n\r\n        <tr><td style="padding:0;border:0;font-size:0;line-height:0;height:0;overflow:hidden;">[HOOK:AFTER_HEADER]</td></tr>\r\n\r\n        <!-- New Order Banner -->\r\n        <tr>\r\n          <td style="background-color: #f59e0b; padding: 32px 30px; text-align: center;">\r\n            <table cellpadding="0" cellspacing="0" border="0" align="center">\r\n              <tr>\r\n                <td style="width: 56px; height: 56px; background-color: rgba(255,255,255,0.2); border-radius: 50%; text-align: center; vertical-align: middle; font-size: 28px; color: #ffffff; font-weight: bold;">\r\n                  $\r\n                </td>\r\n              </tr>\r\n            </table>\r\n            <h1 style="margin: 16px 0 6px 0; font-size: 26px; font-weight: bold; color: #ffffff;">New Order Received</h1>\r\n            <p style="margin: 0; font-size: 15px; color: #fef3c7;">\r\n              A new order has been placed on [SITENAME] for [ORDERAMOUNT].\r\n            </p>\r\n          </td>\r\n        </tr>\r\n\r\n        <!-- Order Details Summary -->\r\n        <tr>\r\n          <td style="padding: 16px 20px 4px 20px;">\r\n            <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #fffbeb; border-radius: 8px;">\r\n              <tr>\r\n                <td style="padding: 14px 20px; font-size: 13px; color: #374151;">\r\n                  <strong>Order #[ORDERID]</strong>&nbsp;&nbsp;&bull;&nbsp;&nbsp;[ORDERDATE]\r\n                  [IF:INVOICENO]&nbsp;&nbsp;&bull;&nbsp;&nbsp;Invoice: [INVOICENO][/IF:INVOICENO]\r\n                  <br><span style="font-size: 12px; color: #6b7280;">Customer: [BILLING_FIRSTNAME] [BILLING_LASTNAME] &lt;[BILLING_EMAIL]&gt;</span>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n\r\n        <tr><td style="padding:0;border:0;font-size:0;line-height:0;height:0;overflow:hidden;">[HOOK:BEFORE_ITEMS]</td></tr>\r\n\r\n        <!-- Order Items Card -->\r\n        <tr>\r\n          <td class="mobile-padding" style="padding: 16px 20px;">\r\n            <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden;">\r\n              <tr>\r\n                <td colspan="4" style="padding: 16px 20px; border-bottom: 1px solid #f3f4f6;">\r\n                  <span style="font-size: 15px; font-weight: bold; color: [TEXT_COLOR];">Items Ordered</span>\r\n                </td>\r\n              </tr>\r\n              <tr>\r\n                <td style="padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;" colspan="2">Product</td>\r\n                <td style="padding: 10px 10px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: center; width: 45px;">Qty</td>\r\n                <td style="padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: right; width: 90px;">Total</td>\r\n              </tr>\r\n              [ITEMS_LOOP]\r\n              <tr>\r\n                <td style="padding: 12px 0 12px 20px; border-top: 1px solid #f3f4f6; vertical-align: top; width: 60px;">\r\n                  [IF:ITEM_IMAGE]\r\n                  <img src="[ITEM_IMAGE]" alt="[ITEM_NAME]" width="50" height="50" style="border-radius: 6px; object-fit: cover; display: block; border: 1px solid #f3f4f6;" />\r\n                  [/IF:ITEM_IMAGE]\r\n                </td>\r\n                <td style="padding: 12px 10px; border-top: 1px solid #f3f4f6; vertical-align: top;">\r\n                  <span style="font-size: 14px; font-weight: 600; color: [TEXT_COLOR];">[ITEM_NAME]</span>\r\n                  [IF:ITEM_SKU]<br /><span style="font-size: 12px; color: #9ca3af;">SKU: [ITEM_SKU]</span>[/IF:ITEM_SKU]\r\n                  [IF:ITEM_OPTIONS]<br /><span style="font-size: 12px; color: #6b7280;">[ITEM_OPTIONS]</span>[/IF:ITEM_OPTIONS]\r\n                  <br /><span style="font-size: 12px; color: #6b7280;">[ITEM_PRICE] each</span>\r\n                </td>\r\n                <td style="padding: 12px 10px; border-top: 1px solid #f3f4f6; text-align: center; vertical-align: top; font-size: 14px; color: [TEXT_COLOR];">[ITEM_QTY]</td>\r\n                <td style="padding: 12px 20px; border-top: 1px solid #f3f4f6; text-align: right; vertical-align: top; font-size: 14px; font-weight: 600; color: [TEXT_COLOR];">[ITEM_TOTAL]</td>\r\n              </tr>\r\n              [/ITEMS_LOOP]\r\n              <tr>\r\n                <td colspan="4" style="padding: 0;">\r\n                  <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f9fafb; border-top: 1px solid #e5e7eb;">\r\n                    <tr>\r\n                      <td style="padding: 10px 20px 2px 20px; font-size: 13px; color: #6b7280;">Subtotal</td>\r\n                      <td style="padding: 10px 20px 2px 20px; font-size: 13px; color: #6b7280; text-align: right;">[SUBTOTAL]</td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="padding: 6px 20px; font-size: 13px; color: #6b7280;">[IF:SHIPPING_AMOUNT]Shipping [IF:SHIPPING_METHOD]([SHIPPING_METHOD])[/IF:SHIPPING_METHOD][/IF:SHIPPING_AMOUNT]</td>\r\n                      <td style="padding: 6px 20px; font-size: 13px; color: #6b7280; text-align: right;">[IF:SHIPPING_AMOUNT][SHIPPING_AMOUNT][/IF:SHIPPING_AMOUNT]</td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="padding: 6px 20px; font-size: 13px; color: #059669;">[IF:DISCOUNT_AMOUNT]Discount [IF:COUPON_CODE]([COUPON_CODE])[/IF:COUPON_CODE][/IF:DISCOUNT_AMOUNT]</td>\r\n                      <td style="padding: 6px 20px; font-size: 13px; color: #059669; text-align: right;">[IF:DISCOUNT_AMOUNT]-[DISCOUNT_AMOUNT][/IF:DISCOUNT_AMOUNT]</td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td colspan="2" style="padding: 0;">[TAX_LINES]</td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="padding: 14px 20px; font-size: 16px; font-weight: bold; color: [TEXT_COLOR]; border-top: 2px solid #e5e7eb;">Total</td>\r\n                      <td style="padding: 14px 20px; font-size: 16px; font-weight: bold; color: [TEXT_COLOR]; text-align: right; border-top: 2px solid #e5e7eb;">[ORDERAMOUNT]</td>\r\n                    </tr>\r\n                  </table>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n\r\n        <tr><td style="padding:0;border:0;font-size:0;line-height:0;height:0;overflow:hidden;">[HOOK:AFTER_ITEMS]</td></tr>\r\n\r\n        <tr><td style="padding:0;border:0;font-size:0;line-height:0;height:0;overflow:hidden;">[HOOK:BEFORE_SHIPPING]</td></tr>\r\n\r\n        <!-- Shipping & Billing Cards -->\r\n        <tr>\r\n          <td class="mobile-padding" style="padding: 0 20px 16px 20px;">\r\n            <table width="100%" cellpadding="0" cellspacing="0" border="0">\r\n              <tr>\r\n                <td class="address-col" style="width: 50%; vertical-align: top; padding-right: 8px;">\r\n                  <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;">\r\n                    <tr>\r\n                      <td style="padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Billing Address</td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="padding: 14px 18px; font-size: 14px; color: [TEXT_COLOR]; line-height: 1.6;">\r\n                        <strong>[BILLING_FIRSTNAME] [BILLING_LASTNAME]</strong>[IF:BILLING_COMPANY]<br />[BILLING_COMPANY][/IF:BILLING_COMPANY]<br />\r\n                        [BILLING_ADDRESS_1][IF:BILLING_ADDRESS_2]<br />[BILLING_ADDRESS_2][/IF:BILLING_ADDRESS_2]<br />\r\n                        [BILLING_CITY], [BILLING_STATE] [BILLING_ZIP]<br />\r\n                        [BILLING_COUNTRY][IF:BILLING_PHONE]<br />[BILLING_PHONE][/IF:BILLING_PHONE]\r\n                      </td>\r\n                    </tr>\r\n                  </table>\r\n                </td>\r\n                <td class="address-col" style="width: 50%; vertical-align: top; padding-left: 8px;">\r\n                  [IF:SHIPPING_FIRSTNAME]\r\n                  <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;">\r\n                    <tr>\r\n                      <td style="padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Shipping Address</td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="padding: 14px 18px; font-size: 14px; color: [TEXT_COLOR]; line-height: 1.6;">\r\n                        <strong>[SHIPPING_FIRSTNAME] [SHIPPING_LASTNAME]</strong><br />\r\n                        [SHIPPING_ADDRESS_1][IF:SHIPPING_ADDRESS_2]<br />[SHIPPING_ADDRESS_2][/IF:SHIPPING_ADDRESS_2]<br />\r\n                        [SHIPPING_CITY], [SHIPPING_STATE] [SHIPPING_ZIP]<br />\r\n                        [SHIPPING_COUNTRY]\r\n                      </td>\r\n                    </tr>\r\n                  </table>\r\n                  [/IF:SHIPPING_FIRSTNAME]\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n\r\n        <!-- Payment Info Card -->\r\n        <tr>\r\n          <td class="mobile-padding" style="padding: 0 20px 16px 20px;">\r\n            <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;">\r\n              <tr>\r\n                <td style="padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;">Payment Information</td>\r\n              </tr>\r\n              <tr>\r\n                <td style="padding: 14px 18px; font-size: 14px; color: [TEXT_COLOR];">\r\n                  <strong>Method:</strong> [PAYMENT_TYPE]\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n\r\n        <tr><td style="padding:0;border:0;font-size:0;line-height:0;height:0;overflow:hidden;">[HOOK:AFTER_PAYMENT]</td></tr>\r\n\r\n        <!-- Customer Note -->\r\n        <tr>\r\n          <td class="mobile-padding" style="padding: 0;">\r\n            [IF:CUSTOMER_NOTE]\r\n            <table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin: 0; padding: 0;">\r\n              <tr>\r\n                <td style="padding: 0 20px 16px 20px;">\r\n                  <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #fffbeb; border: 1px solid #fde68a; border-radius: 10px;">\r\n                    <tr>\r\n                      <td style="padding: 14px 18px; font-size: 13px; font-weight: bold; color: #92400e;">Customer Note</td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="padding: 0 18px 14px 18px; font-size: 14px; color: #78350f; line-height: 1.5;">[CUSTOMER_NOTE]</td>\r\n                    </tr>\r\n                  </table>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n            [/IF:CUSTOMER_NOTE]\r\n          </td>\r\n        </tr>\r\n\r\n        <tr><td style="padding:0;border:0;font-size:0;line-height:0;height:0;overflow:hidden;">[HOOK:BEFORE_FOOTER]</td></tr>\r\n\r\n        <!-- Footer -->\r\n        <tr>\r\n          <td style="padding: 24px 40px; background-color: #ffffff; border-radius: 0 0 12px 12px; border-top: 1px solid #f3f4f6; text-align: center;">\r\n            <p style="font-size: 12px; color: #9ca3af; margin: 0; line-height: 1.6;">[FOOTER_TEXT]</p>\r\n            <p style="font-size: 12px; color: #9ca3af; margin: 8px 0 0 0;">\r\n              &copy; [CURRENT_YEAR] <a href="[SITEURL]" style="color: #9ca3af; text-decoration: underline;">[SITENAME]</a>. All rights reserved.\r\n            </p>\r\n          </td>\r\n        </tr>\r\n\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>','','visual','','','*',1,4);
